SELECT GENERO FROM  (SELECT S.GENERO AS GENERO, COUNT(*) AS PARTICIPACOES FROM LATTES_P_PRODTEC LP JOIN LATTES_PRODTEC PR ON PR.PK = LP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE PR.ANO BETWEEN (CAST(strftime('%Y', 'now') AS INTEGER) - 4) AND CAST(strftime('%Y', 'now') AS INTEGER) AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%engenharia quimica%' AND LOWER(COALESCE(PR.NATUREZA, '')) LIKE '%organizacao%' AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'uru' GROUP BY S.GENERO ORDER BY PARTICIPACOES DESC) AS t